async (page) => {
  // First let me finish this crab fight, then look at the cave more carefully
  // Wait for crab to die
  await page.waitForTimeout(4000);

  // The Spooky Skeleton E5 has click coords from the entity
  // Let me get fresh state and check Skeleton click coords
  const state = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed = JSON.parse(state);
  const skeleton = parsed.nearby_entities.find(e => e.name === 'Spooky Skeleton' && e.on_screen);

  if (skeleton && skeleton.click_x && skeleton.click_y) {
    // Try to click the skeleton's canvas position directly
    await page.evaluate(({x, y}) => {
      const canvas = document.getElementById('canvas');
      canvas.dispatchEvent(new MouseEvent('click', { clientX: x, clientY: y, bubbles: true, ctrlKey: false }));
    }, { x: skeleton.click_x, y: skeleton.click_y });
    await page.waitForTimeout(3000);
  }

  const state2 = await page.evaluate(() => JSON.stringify(window.__latestGameState));
  const parsed2 = JSON.parse(state2);
  return JSON.stringify({
    pos: parsed2.player_position,
    target: parsed2.current_target,
    skeleton_info: skeleton
  });
}

