    await page.evaluate((label) => window.__clickEntity(label), 'E0');
    await page.waitForTimeout(5000);
    const hpS = await page.evaluate(() => window.__latestGameState?.player_stats);
    const gold = await page.evaluate(() => window.__latestGameState?.inventory?.find(i=>i.key==='gold')?.count);
    kills++;
    console.log(`kill ${kills}: hp=${hpS?.hp}/${hpS?.max_hp} gold=${gold}`);
    if ((hpS?.hp||0) < 80) { console.log('low hp wait'); await page.waitForTimeout(10000); }
  }

  const state = await page.evaluate(() => {
    const s = window.__latestGameState;
    return JSON.stringify({pos: s?.player_position, hp: `${s?.player_stats?.hp}/${s?.player_stats?.max_hp}`, gold: s?.inventory?.find(i=>i.key==='gold')?.count});
  });
  return state;
}

